// modules/stripe/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'stripe',
  description: 'Handles Stripe integration for subscription management.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'POST', path: '/stripe/subscribe', auth: true },
    ],
    functions: [],
    types: [],
  },

  sideEffects: [
    'writes to: subscriptions table',
  ],

  invariants: [
    'A subscription must always be bound to exactly one user',
  ],
});

// modules/stripe/handlers/subscribe.ts
import { requireUser } from '/lib/auth';
import { query, transaction } from '/lib/db';
import { Result, ok, err } from '/lib/result';

export async function subscribe(req: Request): Promise<Response> {
  const user = await requireUser(req);
  if (!user) return err({ code: 'UNAUTHORIZED', message: 'User not authenticated' });

  try {
    // Create a Stripe subscription
    const stripe = new Stripe(process.env.STRIPE_SECRET_KEY as string, { apiVersion: '2023-08-16' });
    const subscription = await stripe.subscriptions.create({
      customer: user.stripeCustomerId,
      items: [{ plan: process.env.STRIPE_PLAN_ID as string }],
    });

    // Store the subscription ID in the database
    await transaction(async (client) => {
      await client.query('INSERT INTO subscriptions (user_id, subscription_id) VALUES ($1, $2)', [user.id, subscription.id]);
    });

    return ok({ message: 'Subscription created successfully', subscriptionId: subscription.id });
  } catch (error) {
    console.error(error);
    return err({ code: 'INTERNAL_ERROR', message: 'Failed to create subscription' });
  }
}

// modules/stripe/routes.ts
import { Router } from 'bun';
import { subscribe } from './handlers/subscribe';

const router = new Router();

router.post('/stripe/subscribe', async (req) => {
  const result = await subscribe(req);
  if (result.isOk()) return Response.json(result.value, { status: 200 });
  else return Response.json(result.error, { status: 400 });
});

export default router;

// modules/stripe/module.ts
import { defineModule } from 'aether';
import routes from './routes';

const stripeModule = defineModule({
  name: 'stripe',
  description: 'Handles Stripe integration for subscription management.',
  contract: {
    name: 'stripe',
    description: 'Handles Stripe integration for subscription management.',
    dependencies: { modules: ['auth'] },
    exposes: {
      routes,
      functions: [],
      types: [],
    },
    sideEffects: [
      'writes to: subscriptions table',
    ],
    invariants: [
      'A subscription must always be bound to exactly one user',
    ],
  },
});

export default stripeModule;

